import React from "react";
import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const experienceData = [
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2022-Present",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Senior Product Manager",
    company: "J.P. Morgan",
    date: "2021-2022",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Senior Product Manager",
    company: "ExxonMobil",
    date: "2014-2021",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Senior Product Owner",
    company: "ExxonMobil",
    date: "2013-2014",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Senior Scrum Master",
    company: "ExxonMobil",
    date: "2008-2013",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Supervisor",
    company: "IBM",
    date: "2001-2008",
    icon: <FaBriefcase />,
    type: "job",
  },
  {
    title: "Master of Systems Engineering",
    company: "Universidad Tecnologica Nacional (UTN)",
    date: "2001-2006",
    icon: <FaUniversity />,
    type: "edu",
  },
  {
    title: "Microsoft Certified: Azure Fundamentals",
    company: "Azure",
    date: "2021",
    icon: <FaCloud />,
    type: "cert",
  },
  {
    title: "PMI Agile Certified Practitioner (PMIACP)",
    company: "PMI",
    date: "2019",
    icon: <FaUniversity />,
    type: "cert",
  },
  {
    title: "Certified SAFe® 6 Product Owner/Product Manager",
    company: "Scaled Agile",
    date: "2024",
    icon: <FaUniversity />,
    type: "cert",
  },
  {
    title: "Certified Scrum Product Owner (CSPO)",
    company: "Scrum Alliance",
    date: "2022",
    icon: <FaUniversity />,
    type: "cert",
  },
];

const ExperienceTimeline = () => {
  return (
    <div className="max-w-6xl mx-auto p-4">
      <div className="relative">
        <div className="absolute left-1/2 transform -translate-x-1/2 h-full border-r-2 border-gray-300"></div>
        {experienceData.map((item, index) => {
          const isLeft = index % 2 === 0;
          return (
            <div
              key={index}
              className={`mb-10 flex w-full justify-${isLeft ? "start" : "end"} relative`}
            >
              <div className="w-1/2 px-4">
                <div
                  className={`relative p-4 rounded-lg shadow-md ${
                    item.type === "job"
                      ? "bg-gradient-to-r from-black via-gray-800 to-white text-white"
                      : "bg-gradient-to-r from-blue-600 via-blue-300 to-white text-black"
                  }`}
                >
                  <div className="absolute -top-4 left-1/2 transform -translate-x-1/2 w-8 h-8 bg-white border-2 border-gray-400 rounded-full flex items-center justify-center">
                    <div className="text-gray-700">{item.icon}</div>
                  </div>
                  <p className="text-sm text-gray-200 italic mb-1 text-center">{item.date}</p>
                  <h3 className="text-lg font-semibold leading-tight text-center">
                    {item.title}
                  </h3>
                  <p className="text-sm text-center">{item.company}</p>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default ExperienceTimeline;
